example.code:
export type AuthProvider =
  | { kind: "oidc"; issuer: string; clientId: string }
  | { kind: "credentials"; loginUrl: string }
  | { kind: "none" };

// Consumers get exhaustive narrowing:
function describe(p: AuthProvider): string {
  switch (p.kind) {
    case "oidc": return `OIDC @ ${p.issuer}`;
    case "credentials": return `Credentials @ ${p.loginUrl}`;
    case "none": return "No auth";
  }
}

export type IGRPSession<TUser = { id: string; email: string }> = {
  user: TUser;
  expiresAt: string;
  accessToken?: string;
};
